# crw-rw----+ 1 root kvm 10, 232 Jul 21 10:00 /dev/kvm # System call flow for creating a VM:
# 1. open("/dev/kvm") → get KVM file descriptor
# 2. ioctl(kvm_fd, KVM_GET_API_VERSION) → verify API version (12)
# 3. ioctl(kvm_fd, KVM_CREATE_VM) → create a VM instance
# 4. ioctl(vm_fd, KVM_SET_USER_MEMORY_REGION) → map guest memory
# 5. ioctl(vm_fd, KVM_CREATE_VCPU) → create a virtual CPU
# 6. mmap(vcpu_fd, KVM_RUN) → enter guest mode
# 7. ioctl(vcpu_fd, KVM_RUN) → run the vCPU Minimal KVM example in C: #include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <sys/mman.h>
#include <linux/kvm.h> int main() { int kvm_fd = open("/dev/kvm", O_RDWR | O_CLOEXEC); int api_ver = ioctl(kvm_fd, KVM_GET_API_VERSION, 0); printf("KVM API version: %d\n", api_ver); int vm_fd = ioctl(kvm_fd, KVM_CREATE_VM, 0); // Allocate 4KB of guest memory void *mem = mmap(NULL, 0x1000, PROT_READ | PROT_WRITE, MAP_SHARED | MAP_ANONYMOUS, -1, 0); // Map guest physical address 0x0 to our memory struct kvm_userspace_memory_region region = { .slot = 0, .guest_phys_addr = 0, .memory_size = 0x1000, .userspace_addr = (__u64)mem, }; ioctl(vm_fd, KVM_SET_USER_MEMORY_REGION, &region); // Write x86 HLT instruction at guest address 0x0 // This is the simplest possible guest program char *code = (char *)mem; code[0] = 0xF4; // HLT int vcpu_fd = ioctl(vm_fd, KVM_CREATE_VCPU, 0); // Map the kvm_run structure struct kvm_run *run = mmap(NULL, sizeof(struct kvm_run), PROT_READ | PROT_WRITE, MAP_SHARED, vcpu_fd, 0); // Configure segment registers for flat real mode struct kvm_sregs sregs; ioctl(vcpu_fd, KVM_GET_SREGS, &sregs); sregs.cs.base = 0; sregs.cs.selector = 0; ioctl(vcpu_fd, KVM_SET_SREGS, &sregs); struct kvm_regs regs = { .rip = 0, .rflags = 0x2, // bit 1 always set }; ioctl(vcpu_fd, KVM_SET_REGS, &regs); // Run the VM ioctl(vcpu_fd, KVM_RUN, 0); printf("VM exit reason: %d\n", run->exit_reason); // Expected: KVM_EXIT_HLT (5) return 0;
}

